class Solution {
    private static final int MOD = 1000000007;
    public int countWinningSequences(String s) {
        int n = s.length();
        long[][][] dp = new long[n + 1][3][3];
        dp[0][0][0] = 1;
        dp[0][1][1] = 1;
        dp[0][2][2] = 1;
        for (int i = 1; i <= n; i++) {
            for (int j = 0; j < 3; j++) {
                for (int k = 0; k < 3; k++) {
                    if (s.charAt(i - 1) == 'F') {
                        if (j == 0) {
                            dp[i][1][0] = (dp[i][1][0] + dp[i - 1][k][j]) % MOD;
                            dp[i][2][0] = (dp[i][2][0] + dp[i - 1][k][j]) % MOD;
                        } else if (j == 1) {
                            dp[i][0][1] = (dp[i][0][1] + dp[i - 1][k][j]) % MOD;
                            dp[i][2][1] = (dp[i][2][1] + dp[i - 1][k][j]) % MOD;
                        } else {
                            dp[i][0][2] = (dp[i][0][2] + dp[i - 1][k][j]) % MOD;
                            dp[i][1][2] = (dp[i][1][2] + dp[i - 1][k][j]) % MOD;
                        }
                    } else if (s.charAt(i - 1) == 'W') {
                        if (j == 0) {
                            dp[i][1][0] = (dp[i][1][0] + dp[i - 1][k][j]) % MOD;
                            dp[i][2][0] = (dp[i][2][0] + dp[i - 1][k][j]) % MOD;
                        } else if (j == 1) {
                            dp[i][0][1] = (dp[i][0][1] + dp[i - 1][k][j]) % MOD;
                            dp[i][2][1] = (dp[i][2][1] + dp[i - 1][k][j]) % MOD;
                        } else {
                            dp[i][0][2] = (dp[i][0][2] + dp[i - 1][k][j]) % MOD;
                            dp[i][1][2] = (dp[i][1][2] + dp[i - 1][k][j]) % MOD;
                        }
                    } else {
                        if (j == 0) {
                            dp[i][1][0] = (dp[i][1][0] + dp[i - 1][k][j]) % MOD;
                            dp[i][2][0] = (dp[i][2][0] + dp[i - 1][k][j]) % MOD;
                        } else if (j == 1) {
                            dp[i][0][1] = (dp[i][0][1] + dp[i - 1][k][j]) % MOD;
                            dp[i][2][1] = (dp[i][2][1] + dp[i - 1][k][j]) % MOD;
                        } else {
                            dp[i][0][2] = (dp[i][0][2] + dp[i - 1][k][j]) % MOD;
                            dp[i][1][2] = (dp[i][1][2] + dp[i - 1][k][j]) % MOD;
                        }
                    }
                }
            }
        }
        long ans = 0;
        for (int i = 0; i < 3; i++) {
            for (int j = 0; j < 3; j++) {
                ans = (ans + dp[n][i][j]) % MOD;
            }
        }
        return (int) ans;
    }
}
